POST /webhook/analyse-contract
Body: { contract_text, creator_name, creator_niche, deal_value, brand_name }
O3: RAG Contract Red-Flag Detection ($5,200/year saved in bad deals)

parameters.jsCode:
// ══════════════════════════════════════════════════════
// CreatorIQ — RAG Contract Red-Flag Analysis
// Simulates AI-powered contract clause detection
// In production: embed contract → query ChromaDB RAG →
//   retrieve FTC guidelines + past contracts → Claude analysis
// Value: catches bad clauses worth avg $5,200/year in bad deals
// ══════════════════════════════════════════════════════

const d = $input.first().json;
const contractText = (d.contract_text || '').toLowerCase();
const dealValue    = d.deal_value || 0;
const creatorNiche = (d.creator_niche || 'lifestyle').toLowerCase();

// ── Red-flag clause library (RAG knowledge base simulation) ──
const RED_FLAG_PATTERNS = [
  {
    id:          'RF-001',
    pattern:     'exclusivity',
    severity:    'HIGH',
    clause_type: 'Exclusivity',
    description: 'Broad exclusivity clause detected — may block other brand deals',
    ftc_ref:     'FTC §5 — Unfair or deceptive acts',
    recommendation: 'Negotiate exclusivity to specific product category and 30-day max window',
    estimated_cost: Math.round(dealValue * 0.30)
  },
  {
    id:          'RF-002',
    pattern:     'perpetual license',
    severity:    'CRITICAL',
    clause_type: 'IP / Content Rights',
    description: 'Perpetual content license — brand owns your content forever',
    ftc_ref:     'FTC Endorsement Guides 16 CFR Part 255',
    recommendation: 'Limit license to 12 months or campaign duration. Retain full IP ownership.',
    estimated_cost: Math.round(dealValue * 0.50)
  },
  {
    id:          'RF-003',
    pattern:     'unlimited revisions',
    severity:    'MEDIUM',
    clause_type: 'Scope of Work',
    description: 'Unlimited revision requests — time value risk',
    ftc_ref:     null,
    recommendation: 'Cap at 2 revision rounds. Additional revisions billed at $150/hour.',
    estimated_cost: Math.round(dealValue * 0.10)
  },
  {
    id:          'RF-004',
    pattern:     'morality clause',
    severity:    'MEDIUM',
    clause_type: 'Termination',
    description: 'Broad morality/conduct clause — subjective termination risk',
    ftc_ref:     null,
    recommendation: 'Define specific conduct standards. Mutual morality clause applies to brand too.',
    estimated_cost: dealValue
  },
  {
    id:          'RF-005',
    pattern:     'non-disparagement',
    severity:    'HIGH',
    clause_type: 'Free Speech',
    description: 'Non-disparagement clause may restrict honest audience reviews',
    ftc_ref:     'FTC Endorsement Guides — Material connections must be disclosed',
    recommendation: 'Remove or limit to defamation standard. Honest opinions are legally protected.',
    estimated_cost: Math.round(dealValue * 0.20)
  },
  {
    id:          'RF-006',
    pattern:     'late payment',
    severity:    'LOW',
    clause_type: 'Payment Terms',
    description: 'No late payment penalty clause — payment delays unprotected',
    ftc_ref:     null,
    recommendation: 'Add 1.5%/month interest on invoices unpaid beyond 30 days.',
    estimated_cost: Math.round(dealValue * 0.05)
  },
  {
    id:          'RF-007',
    pattern:     'governing law',
    severity:    'MEDIUM',
    clause_type: 'Jurisdiction',
    description: 'Governing law set to brand\'s jurisdiction — may disadvantage creator',
    ftc_ref:     null,
    recommendation: 'Negotiate for creator\'s home state jurisdiction or neutral arbitration.',
    estimated_cost: Math.round(dealValue * 0.08)
  }
];

// ── FTC disclosure requirements by niche ──
const FTC_REQUIREMENTS = {
  finance:    { disclosure: 'REQUIRED — Financial products require full FTC §205 disclosure', risk: 'HIGH' },
  health:     { disclosure: 'REQUIRED — Health claims require substantiation per FTC Act', risk: 'HIGH' },
  fitness:    { disclosure: 'REQUIRED — Health/fitness claims require substantiation', risk: 'HIGH' },
  tech:       { disclosure: 'STANDARD — #ad or #sponsored disclosure required', risk: 'MEDIUM' },
  lifestyle:  { disclosure: 'STANDARD — #ad or #sponsored disclosure required', risk: 'LOW' },
  gaming:     { disclosure: 'STANDARD — #ad or #sponsored disclosure required', risk: 'LOW' },
  business:   { disclosure: 'STANDARD — Business opportunity disclosures may apply', risk: 'MEDIUM' }
};

const ftcNiche = FTC_REQUIREMENTS[creatorNiche] || FTC_REQUIREMENTS.lifestyle;

// ── Scan contract text for red flags ──
const detected = RED_FLAG_PATTERNS.filter(rf =>
  contractText.includes(rf.pattern)
);

const criticalFlags = detected.filter(f => f.severity === 'CRITICAL');
const highFlags     = detected.filter(f => f.severity === 'HIGH');
const mediumFlags   = detected.filter(f => f.severity === 'MEDIUM');
const lowFlags      = detected.filter(f => f.severity === 'LOW');

const totalRisk = detected.reduce((sum, f) => sum + (f.estimated_cost || 0), 0);

// ── Contract health score (100 = clean, 0 = dangerous) ──
const penaltyMap = { CRITICAL: 35, HIGH: 20, MEDIUM: 10, LOW: 5 };
const penalty    = detected.reduce((sum, f) => sum + (penaltyMap[f.severity] || 0), 0);
const healthScore = Math.max(0, 100 - penalty);

let verdict = 'PASS';
if (healthScore < 40)  verdict = 'REJECT';
else if (healthScore < 70) verdict = 'NEGOTIATE';

// ── Build full analysis report ──
const analysis = {
  analysis_id:    d.analysis_id,
  creator_name:   d.creator_name,
  brand_name:     d.brand_name,
  deal_value:     dealValue,
  submitted_at:   d.submitted_at,

  contract_health: {
    score:         healthScore,
    verdict:       verdict,
    risk_summary:  `${detected.length} red flags detected (${criticalFlags.length} critical, ${highFlags.length} high, ${mediumFlags.length} medium, ${lowFlags.length} low)`,
    total_risk_exposure: totalRisk
  },

  ftc_compliance: {
    niche:       creatorNiche,
    requirement: ftcNiche.disclosure,
    risk_level:  ftcNiche.risk,
    action:      'Add FTC-compliant disclosure to all sponsored content'
  },

  red_flags: detected,

  top_priority: detected.length > 0
    ? detected.sort((a,b) => {
        const order = { CRITICAL: 0, HIGH: 1, MEDIUM: 2, LOW: 3 };
        return order[a.severity] - order[b.severity];
      })[0]
    : null,

  recommendations: detected.map(f => `[${f.severity}] ${f.clause_type}: ${f.recommendation}`),

  estimated_value_protected: totalRisk,

  workflow: 'O3 — RAG Contract Analysis',
  rag_note: 'Production: embed contract → ChromaDB semantic search → retrieve FTC docs + past contracts → Claude-3.5 analysis'
};

return [{ json: { ...d, analysis } }];

nodes.notes:
Returns full contract analysis to frontend:
{ verdict, health_score, red_flags[], recommendations[], ftc_compliance }
CORS headers allow any web frontend to call this endpoint.
